import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Language Surface","description":"","frontmatter":{},"headers":[],"relativePath":"lang.md","filePath":"lang.md"}'),l={name:"lang.md"};function o(i,e,r,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="language-surface" tabindex="-1">Language Surface <a class="header-anchor" href="#language-surface" aria-label="Permalink to &quot;Language Surface&quot;">​</a></h1><p>LinkedQL extends SQL across three core areas: how data is shaped and related, how state is mutated, and how execution correctness is enforced.</p><hr><h2 id="object-syntax" tabindex="-1">Object Syntax <a class="header-anchor" href="#object-syntax" aria-label="Permalink to &quot;Object Syntax&quot;">​</a></h2><p>LinkedQL extends SQL with an &quot;object&quot; paradigm that maps to the conventional application-level object thinking.</p><h3 id="meet-json-literals" tabindex="-1">Meet JSON Literals <a class="header-anchor" href="#meet-json-literals" aria-label="Permalink to &quot;Meet JSON Literals&quot;">​</a></h3><p><strong>JSON Literals</strong> let you define the exact shape your application expects directly in SQL.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    { first: first_name, last: last_name } AS name,</span></span>
<span class="line"><span style="color:#C3E88D;">    { email, phone: phone_number } AS contact</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM users</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No remapping step or post-processing code. The query itself defines the shape.</p><h3 id="meet-deeprefs" tabindex="-1">Meet DeepRefs <a class="header-anchor" href="#meet-deeprefs" aria-label="Permalink to &quot;Meet DeepRefs&quot;">​</a></h3><p><strong>DeepRefs</strong> let you follow relationships directly in SQL using simple arrow notations.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> posts </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    title,</span></span>
<span class="line"><span style="color:#C3E88D;">    author ~&gt; {</span></span>
<span class="line"><span style="color:#C3E88D;">      id,</span></span>
<span class="line"><span style="color:#C3E88D;">      name,</span></span>
<span class="line"><span style="color:#C3E88D;">      profile ~&gt; { avatar_url }</span></span>
<span class="line"><span style="color:#C3E88D;">    } AS author</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM posts</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE published = true</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No need for an ORM or manual JOIN logic.</p><p>If you&#39;ve defined foreign key relationships in your tables, you can traverse them directly.</p><p>The above expresses the data the way the application already understands it: <em>a post has an author, an author has a profile</em></p><h3 id="the-broader-idea" tabindex="-1">The Broader Idea <a class="header-anchor" href="#the-broader-idea" aria-label="Permalink to &quot;The Broader Idea&quot;">​</a></h3><p>Database logic is rarely just about returning rows. It is about aligning SQL semantics with application-level intent.</p><ul><li>navigating relationships</li><li>shaping results into application-ready structures</li><li>coordinating read and write intent</li></ul><p>This logic often spills out of SQL into post-processing layers, with much glue code. LinkedQL pulls this logic back into the query itself.</p><hr><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>DeepRefs</strong></td><td style="text-align:left;">Direct relationship traversal in SQL</td><td style="text-align:left;"><a href="/lang/deeprefs">DeepRefs</a></td></tr><tr><td style="text-align:left;"><strong>JSON Literals</strong></td><td style="text-align:left;">Direct structuring in SQL</td><td style="text-align:left;"><a href="/lang/json-literals">JSON Literals</a></td></tr></tbody></table><hr><h2 id="declarative-dml" tabindex="-1">Declarative DML <a class="header-anchor" href="#declarative-dml" aria-label="Permalink to &quot;Declarative DML&quot;">​</a></h2><p>LinkedQL replaces procedural mutation patterns in SQL with declarative expressions. Instead of expressing how to modify data, you express the intended final state.</p><h3 id="meet-upsert" tabindex="-1">Meet UPSERT <a class="header-anchor" href="#meet-upsert" aria-label="Permalink to &quot;Meet UPSERT&quot;">​</a></h3><p><strong>UPSERT</strong> expresses insert-or-update as a single declarative mutation, removing the need for existence checks or branching logic.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  UPSERT INTO users (id, name, email)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada Lovelace&#39;, &#39;ada@math.org&#39;)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If the record exists, it is updated. If not, it is created.</p><p>No conditional pre-checks or duplicated mutation logic across layers. One statement expresses the full intent.</p><h3 id="the-broader-idea-1" tabindex="-1">The Broader Idea <a class="header-anchor" href="#the-broader-idea-1" aria-label="Permalink to &quot;The Broader Idea&quot;">​</a></h3><p>Mutation logic is rarely about individual rows — it is about reaching a consistent state.</p><p>Traditional DML forces applications into procedural patterns:</p><ul><li>explicit existence checks</li><li>branching control flow</li><li>duplicated insert/update paths</li></ul><p>Single-statement operations collapse this flow into a single declarative step.</p><h3 id="documentation-1" tabindex="-1">Documentation <a class="header-anchor" href="#documentation-1" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>UPSERT</strong></td><td style="text-align:left;">Unified insert-or-update intent</td><td style="text-align:left;"><a href="/lang/upsert">UPSERT</a></td></tr></tbody></table><hr><h2 id="type-safety" tabindex="-1">Type Safety <a class="header-anchor" href="#type-safety" aria-label="Permalink to &quot;Type Safety&quot;">​</a></h2><p>LinkedQL allows queries to declare constraints that are often implicit but required for correctness.</p><h3 id="meet-version-binding" tabindex="-1">Meet Version Binding <a class="header-anchor" href="#meet-version-binding" aria-label="Permalink to &quot;Meet Version Binding&quot;">​</a></h3><p><strong>Version Binding</strong> allows queries to explicitly declare the schema version they depend on, enabling safe evolution of applications and databases in parallel.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> users </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name, email</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM users@2_1</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If the database does not satisfy the declared version, the query fails early instead of executing under incompatible assumptions.</p><p>Contract mismatches are surfaced at the query boundary, not discovered indirectly through runtime behavior. These constraints can also be validated statically before execution.</p><h3 id="the-broader-idea-2" tabindex="-1">The Broader Idea <a class="header-anchor" href="#the-broader-idea-2" aria-label="Permalink to &quot;The Broader Idea&quot;">​</a></h3><p>Schema evolution is rarely isolated. It introduces:</p><ul><li>breaking changes across services</li><li>migration coordination overhead</li><li>fragile backward compatibility layers</li></ul><p>Version Binding makes evolution explicit at the query level, allowing applications to pin behavior deterministically and migrate gradually without hidden coupling.</p><blockquote><p>Version binding is currently only supported in FlashQL</p></blockquote><h3 id="documentation-2" tabindex="-1">Documentation <a class="header-anchor" href="#documentation-2" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Version Binding</strong></td><td style="text-align:left;">Query-level version targeting</td><td style="text-align:left;"><a href="/lang/version-binding">Version Binding</a></td></tr></tbody></table><hr><h2 id="sql-reference" tabindex="-1">SQL Reference <a class="header-anchor" href="#sql-reference" aria-label="Permalink to &quot;SQL Reference&quot;">​</a></h2><p>LinkedQL builds on standard SQL, extending some areas while leaving others unchanged or not yet supported.</p><p>A full reference of supported and unsupported SQL features is planned and will document:</p><ul><li>supported SQL syntax and behavior</li><li>unsupported or partially supported features</li></ul>`,57)])])}const y=a(l,[["render",o]]);export{u as __pageData,y as default};
